def checkout(conn, tenant_id, worker_id):
    row = conn.execute(
        "SELECT id FROM issues WHERE tenant_id = ? AND status = 'todo' ORDER BY priority LIMIT 1",
        (tenant_id,)
    ).fetchone()
    if row is None:
        return None
    issue_id = row[0]
    cursor = conn.execute(
        "UPDATE issues SET status = 'in_progress', lease_owner = ? WHERE id = ? AND tenant_id = ? AND status = 'todo'",
        (worker_id, issue_id, tenant_id)
    )
    if cursor.rowcount == 0:
        return None
    return issue_id

